function buildSavingPrompt(ctx, coletado, saving, resumoProjeto) {
  const detalhes = `RESUMO DO PROJETO (contexto da etapa anterior):
${resumoProjeto}

DETALHES T\xC9CNICOS APROVADOS:
- Nome: ${coletado.nome_projeto}
- O que faz: ${coletado.o_que_faz}
- Execu\xE7\xE3o: ${coletado.execucao}
- Fluxo: ${coletado.fluxo}
- Ferramenta: ${ctx.ferramenta}`;
  const horasAntes = saving.horas_antes ?? 0;
  const horasDepois = saving.horas_depois ?? 0;
  const economiaHoras = saving.economia_horas_mes ?? horasAntes - horasDepois;
  const valorHora = saving.valor_hora ?? 0;
  const economiaReais = saving.economia_reais_mes ?? economiaHoras * valorHora;
  return `Voc\xEA \xE9 o assistente de an\xE1lise de ganhos financeiros de projetos de automa\xE7\xE3o do GoGroup.
A documenta\xE7\xE3o t\xE9cnica do projeto j\xE1 foi aprovada. Agora seu objetivo \xE9 VALIDAR as horas informadas e construir o memorial de c\xE1lculo.

${detalhes}

DADOS J\xC1 DEFINIDOS PELO USU\xC1RIO (N\xC3O pergunte sobre eles):
- Cargo de quem executava a tarefa: ${saving.cargo ?? "n\xE3o informado"}
- Horas gastas antes da automa\xE7\xE3o: ${horasAntes}h/m\xEAs
- Horas gastas ap\xF3s a automa\xE7\xE3o: ${horasDepois}h/m\xEAs
- Economia de horas: ${economiaHoras}h/m\xEAs
- Tipo de saving: ${saving.tipo_saving ?? "n\xE3o definido"} (${saving.tipo_saving === "mensal" ? "recorrente todo m\xEAs" : "economia \xFAnica"})

O VALOR EM REAIS J\xC1 FOI CALCULADO PELO SISTEMA \u2014 N\xC3O MENCIONE valores em R$ para o usu\xE1rio. Foque apenas nas HORAS.

SEU OBJETIVO: validar que as ${horasAntes}h/m\xEAs ANTES da automa\xE7\xE3o s\xE3o reais e justific\xE1veis, e montar o memorial_calculo.

ESTADO ATUAL:
${JSON.stringify(saving, null, 2)}

COMO CONDUZIR:
1. Comece perguntando sobre o processo manual: o que exatamente era feito nessas ${horasAntes}h por m\xEAs? Detalhe a rotina passo a passo.
2. Fa\xE7a UMA pergunta por vez, focada em fatos concretos sobre o processo manual anterior.
3. Monte o memorial_calculo conforme o usu\xE1rio responde \u2014 N\xC3O pe\xE7a para ele escrever.
4. Quando a justificativa for concreta e a conta fechar, gere o PREVIEW.

VALIDA\xC7\xC3O DE HORAS \u2014 OBRIGAT\xD3RIO:
- NUNCA aceite as horas "de cara". O usu\xE1rio DEVE detalhar a rotina manual: quais tarefas, com que frequ\xEAncia, quanto tempo cada uma, quantas pessoas executavam.
- Fa\xE7a a conta: se o usu\xE1rio diz "50 cadastros por m\xEAs, 15 min cada", isso d\xE1 ~12h \u2014 se ele informou ${horasAntes}h, aponte a discrep\xE2ncia e pe\xE7a para explicar.
- Se a estimativa parecer inflada para o tipo de tarefa, questione diretamente.
- Cruze com o contexto do projeto: se o fluxo t\xE9cnico \xE9 simples (3-4 etapas), muitas horas manuais n\xE3o fazem sentido. Desafie.
- Se ap\xF3s o detalhamento as horas reais forem diferentes das informadas, atualize economia_horas_mes no saving e recalcule.

REGRAS ANTI-EXTRAPOLA\xC7\xC3O:
- Saving deve refletir ganho REAL e comprov\xE1vel.
- Se o processo manual n\xE3o existia, saving de horas \xE9 0.
- O memorial precisa ter l\xF3gica verific\xE1vel: frequ\xEAncia \xD7 tempo \xD7 pessoas = total de horas.

Portugu\xEAs brasileiro, tom direto. Acentua\xE7\xE3o correta.

FORMATO \u2014 APENAS JSON v\xE1lido:

Pergunta:
{"type":"question","content":"sua pergunta","saving":{...campos atualizados}}

Op\xE7\xF5es:
{"type":"options","question":"pergunta","options":["op\xE7\xE3o 1","op\xE7\xE3o 2","op\xE7\xE3o 3"],"saving":{...campos atualizados}}

Preview (quando justificativa concreta e memorial completo):
{"type":"preview","content":"## Memorial de C\xE1lculo\\n\\n...memorial formatado em markdown com a l\xF3gica completa...\\n\\n**Resumo:**\\n- Economia: ${economiaHoras}h/m\xEAs\\n- Tipo: ${saving.tipo_saving ?? "mensal"}\\n\\nEst\xE1 correto? Pode aprovar ou pedir ajustes.","saving":{...todos os campos}}`;
}
function buildSavingPreviewPrompt(saving) {
  return `Voc\xEA \xE9 o assistente de an\xE1lise financeira do GoGroup. O usu\xE1rio est\xE1 revisando o memorial de saving.

MEMORIAL ATUAL:
${JSON.stringify(saving, null, 2)}

O usu\xE1rio pode:
1. APROVAR \u2014 "ok", "aprovado", "pode enviar", "sim", etc.
2. PEDIR AJUSTES \u2014 apontar corre\xE7\xF5es.

FORMATO \u2014 APENAS JSON v\xE1lido:

Se aprovado:
{"type":"complete","content":"Memorial aprovado! Sua submiss\xE3o est\xE1 completa e ser\xE1 enviada para an\xE1lise.","saving":{...campos finais}}

Se ajuste + novo preview:
{"type":"preview","content":"## Memorial de C\xE1lculo\\n\\n...corrigido...\\n\\nFiz os ajustes. Pode aprovar?","saving":{...campos corrigidos}}

Se precisa de clarifica\xE7\xE3o:
{"type":"question","content":"pergunta","saving":{...campos atuais}}`;
}
async function runOrchestrator(ctx, history, fase = "doc", coletado = documentacaoVazia(), saving = savingVazio(), resumoProjeto = "", tipos_projeto = ["saving"], receita = receitaVazia()) {
  let systemPrompt;
  switch (fase) {
    case "doc":
      systemPrompt = buildDocPrompt(ctx, coletado);
      break;
    case "doc_preview":
      systemPrompt = buildDocPreviewPrompt(ctx, coletado);
      break;
    case "saving":
      systemPrompt = buildSavingPrompt(ctx, coletado, saving, resumoProjeto);
      break;
    case "saving_preview":
      systemPrompt = buildSavingPreviewPrompt(saving);
      break;
    case "receita":
      systemPrompt = buildReceitaPrompt(ctx, coletado, receita, resumoProjeto);
      break;
    case "receita_preview":
      systemPrompt = buildReceitaPreviewPrompt(receita);
      break;
    default:
      systemPrompt = buildDocPrompt(ctx, coletado);
  }
  const messages = [
    { role: "system", content: systemPrompt },
    ...history.map((m) => ({ role: m.role, content: m.content }))
  ];
  if (history.length === 0) {
    const temDoc = ctx.doc_texto && ctx.doc_texto.trim().length > 10;
    if (fase === "doc") {
      const camposPreenchidos = Object.values(coletado).filter((v) => v !== null).length;
      const todosPreenchidos = camposPreenchidos >= 7;
      const muitosPreenchidos = camposPreenchidos >= 5;
      let sistemaMsg;
      if (todosPreenchidos) {
        sistemaMsg = "[SISTEMA] O sistema leu todos os arquivos do projeto e preencheu os 7 campos automaticamente. Gere o PREVIEW DIRETO agora, sem cumprimentos, sem listar o que foi extra\xEDdo e sem fazer perguntas.";
      } else if (muitosPreenchidos) {
        const nulos = Object.entries(coletado).filter(([, v]) => v === null).map(([k]) => k).join(", ");
        sistemaMsg = `[SISTEMA] O sistema leu os arquivos e preencheu ${camposPreenchidos}/7 campos do c\xF3digo. Os campos ainda em null (${nulos}) precisam de contexto de neg\xF3cio que n\xE3o est\xE1 no c\xF3digo. Cumprimente em 1 frase curta explicando que a an\xE1lise t\xE9cnica est\xE1 pronta e voc\xEA precisa de mais contexto, depois fa\xE7a UMA pergunta objetiva sobre o campo null mais relevante.`;
      } else if (temDoc) {
        sistemaMsg = "[SISTEMA] O sistema leu os arquivos do projeto mas conseguiu pouca informa\xE7\xE3o. Cumprimente brevemente e fa\xE7a a primeira pergunta sobre o campo mais importante ainda em null. Seja direto.";
      } else {
        sistemaMsg = "[SISTEMA] Nenhum arquivo foi enviado. Cumprimente em 1 frase curta e comece a coletar as informa\xE7\xF5es do projeto via conversa. Seja direto.";
      }
      messages.push({ role: "user", content: sistemaMsg });
    } else if (fase === "saving") {
      const horasAntes = saving.horas_antes ?? 0;
      const horasDepois = saving.horas_depois ?? 0;
      const economiaHoras = horasAntes - horasDepois;
      messages.push({
        role: "user",
        content: `[SISTEMA] O usu\xE1rio informou: cargo "${saving.cargo ?? "?"}", ${horasAntes}h/m\xEAs antes da automa\xE7\xE3o, ${horasDepois}h/m\xEAs depois. Economia declarada: ${economiaHoras}h/m\xEAs, tipo: ${saving.tipo_saving ?? "mensal"}. Apresente-se em UMA frase curta e fa\xE7a a primeira pergunta concreta \u2014 pe\xE7a para o usu\xE1rio detalhar passo a passo o que era feito manualmente nessas ${horasAntes}h. Sempre termine com uma pergunta.`
      });
    } else if (fase === "receita") {
      messages.push({
        role: "user",
        content: `[SISTEMA] Projeto de receita incremental, frequ\xEAncia: ${receita.tipo_saving ?? "mensal"}. Apresente-se em UMA frase curta explicando que agora vamos avaliar o ganho de receita do projeto. Fa\xE7a a primeira pergunta concreta sobre quanto de receita nova o projeto gera e como esse valor foi estimado. Sempre termine com uma pergunta.`
      });
    }
  }
  const temperature = fase === "doc" || fase === "doc_preview" ? 0.2 : 0.4;
  log2(`Chamando LLM \u2014 fase: ${fase}, hist\xF3rico: ${history.length} msgs, temperatura: ${temperature}`);
  let raw;
  try {
    raw = await llmChat(messages, { jsonMode: true, temperature });
    log2(`LLM respondeu: ${raw.slice(0, 200)}${raw.length > 200 ? "..." : ""}`);
  } catch (llmErr) {
    const msg = llmErr instanceof Error ? llmErr.message : String(llmErr);
    log2(`Erro no LLM: ${msg}`);
    throw new Error(`Falha na chamada ao modelo de IA: ${msg}`);
  }
  const hasSaving = tipos_projeto.includes("saving");
  const hasReceita = tipos_projeto.includes("receita_incremental");
  let parsed;
  try {
    parsed = JSON.parse(raw);
  } catch {
    log2("Falha ao parsear JSON, tentando recuperar campos do texto truncado...");
    const typeMatch = raw.match(/"type"\s*:\s*"(\w+)"/);
    const contentMatch = raw.match(/"content"\s*:\s*"([\s\S]*?)(?:"\s*,\s*"(?:coletado|saving|receita|options)|"\s*})/);
    const recoveredType = typeMatch?.[1] ?? "question";
    let recoveredContent = contentMatch?.[1] ?? "";
    if (recoveredContent) {
      try {
        recoveredContent = JSON.parse(`"${recoveredContent}"`);
      } catch {
      }
    } else {
      const lastResort = raw.match(/"content"\s*:\s*"([\s\S]+)/);
      if (lastResort) {
        recoveredContent = lastResort[1].replace(/"\s*,?\s*"coletado[\s\S]*$/, "").replace(/\\n/g, "\n").replace(/\\"/g, '"');
      } else {
        recoveredContent = "Houve um erro ao processar a resposta da IA. Por favor, tente novamente.";
      }
    }
    log2(`Recuperado do JSON truncado: type="${recoveredType}", content=${recoveredContent.length} chars`);
    const fallbackResult = {
      type: recoveredType,
      content: recoveredContent,
      fase,
      coletado,
      saving,
      receita
    };
    if (recoveredType === "preview") {
      if (fase === "doc") fallbackResult.fase = "doc_preview";
      else if (fase === "saving") fallbackResult.fase = "saving_preview";
      else if (fase === "receita") fallbackResult.fase = "receita_preview";
    } else if (recoveredType === "complete") {
      if (fase === "doc_preview") {
        fallbackResult.fase = hasSaving ? "saving" : "receita";
      } else if (fase === "saving_preview") {
        fallbackResult.fase = hasReceita ? "receita" : "completo";
      } else if (fase === "receita_preview") {
        fallbackResult.fase = "completo";
      }
    }
    return fallbackResult;
  }
  const type = parsed.type ?? "question";
  const content = parsed.content ?? parsed.question ?? raw;
  const result2 = {
    type,
    fase,
    coletado: parsed.coletado ?? coletado,
    saving: parsed.saving ?? saving,
    receita: parsed.receita ?? receita,
    ...type === "options" ? { question: content, options: parsed.options ?? ["", "", ""] } : { content }
  };
  if (type === "preview") {
    if (fase === "doc") result2.fase = "doc_preview";
    else if (fase === "saving") result2.fase = "saving_preview";
    else if (fase === "receita") result2.fase = "receita_preview";
  }
  if (type === "complete") {
    if (fase === "doc_preview") {
      result2.fase = hasSaving ? "saving" : "receita";
    } else if (fase === "saving_preview") {
      result2.fase = hasReceita ? "receita" : "completo";
    } else if (fase === "receita_preview") {
      result2.fase = "completo";
    }
  }
  log2(`Resultado: type="${result2.type}", fase="${result2.fase}"`);
  return result2;
}

// src/lib/agents/doc-compiler.ts
var SYSTEM_PROMPT = `Voc\xEA \xE9 um especialista em documenta\xE7\xE3o de projetos de automa\xE7\xE3o corporativa do GoGroup.
Gere uma documenta\xE7\xE3o t\xE9cnica profissional e completa com base nas informa\xE7\xF5es coletadas.

A documenta\xE7\xE3o final deve seguir EXATAMENTE esta estrutura de 6 se\xE7\xF5es:

1. **O que faz** \u2014 Par\xE1grafo objetivo de 2-4 frases: qual problema resolve, para quem resolve, e qual o resultado da execu\xE7\xE3o.
2. **Execu\xE7\xE3o** \u2014 Como o projeto \xE9 acionado (trigger manual, schedule com hor\xE1rio/frequ\xEAncia, webhook, evento, etc.).
3. **Depend\xEAncias** \u2014 Lista de TODOS os servi\xE7os externos, APIs, credenciais e acessos necess\xE1rios.
4. **Fluxo** \u2014 Sequ\xEAncia l\xF3gica e completa das etapas da execu\xE7\xE3o, do in\xEDcio ao fim. Incluir ramifica\xE7\xF5es condicionais (IF/ELSE) quando houver.
5. **Configurar antes de usar** \u2014 Passos m\xEDnimos para algu\xE9m que acabou de receber o projeto conseguir rod\xE1-lo.
6. **Aten\xE7\xE3o** \u2014 Riscos reais, limita\xE7\xF5es conhecidas, pontos fr\xE1geis. N\xE3o invente riscos gen\xE9ricos.

CRIT\xC9RIOS DE QUALIDADE:
- "O que faz" deve ser compreens\xEDvel por algu\xE9m que nunca viu o projeto.
- "Depend\xEAncias" deve listar TODOS os servi\xE7os mencionados \u2014 n\xE3o omita nenhum.
- "Fluxo" deve ser uma sequ\xEAncia l\xF3gica sem pular etapas.
- "Aten\xE7\xE3o" s\xF3 deve ter itens reais. Se n\xE3o houver riscos claros, use: "Nenhum risco cr\xEDtico identificado no momento."
- N\xC3O repita informa\xE7\xF5es entre se\xE7\xF5es.
- Escreva em portugu\xEAs brasileiro com acentua\xE7\xE3o correta.

Responda APENAS com JSON v\xE1lido seguindo exatamente a estrutura abaixo:
{
  "titulo": "nome do projeto",
  "responsavel": { "nome": "...", "email": "...", "area": "..." },
  "ferramenta": "...",
  "membros": ["..."],
  "o_que_faz": "par\xE1grafo descritivo",
  "execucao": "descri\xE7\xE3o do trigger/agendamento",
  "dependencias": [{"servico": "Nome", "descricao": "para qu\xEA \xE9 usado"}],
  "fluxo": [{"etapa": "Nome", "descricao": "o que acontece", "condicoes": [{"se": "condi\xE7\xE3o", "acao": "a\xE7\xE3o"}]}],
  "configurar_antes": ["passo 1", "passo 2"],
  "atencao": [{"titulo": "T\xEDtulo", "descricao": "descri\xE7\xE3o e recomenda\xE7\xE3o"}],
  "gerado_em": "ISO date string"
}`;
async function compilarDocumentacao(ctx, coletado) {
  const userMsg = `Gere a documenta\xE7\xE3o com base nestas informa\xE7\xF5es coletadas:

CONTEXTO DO PROJETO:
- Respons\xE1vel: ${ctx.responsavel_nome} (${ctx.responsavel_email})
- \xC1rea: ${ctx.area ?? "N\xE3o informada"}
- Ferramenta: ${ctx.ferramenta}
- Membros: ${ctx.membros.join(", ") || "N\xE3o informado"}

INFORMA\xC7\xD5ES COLETADAS VIA CHAT:
- Nome do projeto: ${coletado.nome_projeto}
- O que faz: ${coletado.o_que_faz}
- Execu\xE7\xE3o (trigger): ${coletado.execucao}
- Depend\xEAncias: ${coletado.dependencias}
- Fluxo: ${coletado.fluxo}
- Configurar antes de usar: ${coletado.configurar_antes}
- Pontos de aten\xE7\xE3o: ${coletado.atencao}`;
  const raw = await llmChat(
    [
      { role: "system", content: SYSTEM_PROMPT },
      { role: "user", content: userMsg }
    ],
    { jsonMode: true, temperature: 0.3 }
  );
  const doc = JSON.parse(raw);
  if (!doc.gerado_em) {
    doc.gerado_em = (/* @__PURE__ */ new Date()).toISOString();
  }
  return doc;
}

