var BREVO_API_URL = "https://api.brevo.com/v3/smtp/email";
async function sendEmail(to, subject, html) {
  const apiKey = process.env.BREVO_API_KEY;
  const from = process.env.EMAIL_FROM ?? "noreply@gocase.com";
  if (!apiKey) throw new Error("BREVO_API_KEY n\xE3o configurada.");
  const res = await fetch(BREVO_API_URL, {
    method: "POST",
    headers: {
      "api-key": apiKey,
      "Content-Type": "application/json"
    },
    body: JSON.stringify({
      sender: { name: "GoDocs", email: from },
      to: [{ email: to }],
      subject,
      htmlContent: html
    })
  });
  if (!res.ok) {
    const err3 = await res.text();
    throw new Error(`Brevo error ${res.status}: ${err3}`);
  }
}
